class TownShipCodModel {  bool? success;  int? total;  bool? canLoadMore;  List<TownShipCodData>? data;  TownShipCodModel({this.success, this.total, this.canLoadMore, this.data});  TownShipCodModel.fromJson(Map<String, dynamic> json) {    success = json['success'];    total = json['total'];    canLoadMore = json['can_load_more'];    if (json['data'] != null) {      data = <TownShipCodData>[];      json['data'].forEach((v) {        data!.add(new TownShipCodData.fromJson(v));      });    }  }  Map<String, dynamic> toJson() {    final Map<String, dynamic> data = new Map<String, dynamic>();    data['success'] = this.success;    data['total'] = this.total;    data['can_load_more'] = this.canLoadMore;    if (this.data != null) {      data['data'] = this.data!.map((v) => v.toJson()).toList();    }    return data;  }}class TownShipCodData {  int? id;  int? regionId;  String? city;  String? fee;  int? cod;  Region? region;  TownShipCodData({this.id, this.regionId, this.city, this.fee, this.cod, this.region});  TownShipCodData.fromJson(Map<String, dynamic> json) {    id = json['id'];    regionId = json['region_id'];    city = json['city'];    fee = json['fee'];    cod = json['cod'];    region =    json['region'] != null ? new Region.fromJson(json['region']) : null;  }  Map<String, dynamic> toJson() {    final Map<String, dynamic> data = new Map<String, dynamic>();    data['id'] = this.id;    data['region_id'] = this.regionId;    data['city'] = this.city;    data['fee'] = this.fee;    data['cod'] = this.cod;    if (this.region != null) {      data['region'] = this.region!.toJson();    }    return data;  }}class Region {  int? id;  String? name;  Region({this.id, this.name});  Region.fromJson(Map<String, dynamic> json) {    id = json['id'];    name = json['name'];  }  Map<String, dynamic> toJson() {    final Map<String, dynamic> data = new Map<String, dynamic>();    data['id'] = this.id;    data['name'] = this.name;    return data;  }}